"""
CodeBench shim for `pywebview` (https://pywebview.flowrl.com/).

The real pywebview spawns native OS windows (Cocoa / GTK / WinForms / Qt)
and embeds a system web view. None of those backends work in our iOS
embedded-Python sandbox — no fork/exec, no AppKit access, no separate
process. So we route every `webview.create_window(...)` call into the
in-app preview pane via the same file-IPC channel the LaTeX engine
already uses (`$TMPDIR/latex_signals/preview_request.txt`).

What works:
    import webview
    webview.create_window("Title", "https://example.com")
    webview.create_window("Title", html="<h1>Hi</h1>")
    webview.create_window("Title", "file:///path/to/index.html")
    webview.create_window("Title", "/absolute/path/to/file.html")
    webview.start()

    # Window methods on the returned object:
    w = webview.create_window("My App", html="<button>x</button>")
    w.load_url("https://other.example")
    w.load_html("<h2>Updated</h2>")
    w.set_title("New title")
    w.evaluate_js("document.body.style.background = 'red'")
    w.destroy()        # hides the preview

What's stubbed (warnings printed, calls succeed silently):
    js_api=...         # JS→Python callbacks (would need WKScriptMessage bridge)
    confirmation_dialog, file_dialog, save_file_dialog
    fullscreen, frameless, on_top, resizable
    multiple windows  — only the most recent one is shown in the preview

What's not supported:
    webview.GUI selection ("cocoa"/"qt"/...)
    System-tray menus, native menubars
    Drag-and-drop from the OS
"""
from __future__ import annotations

import json
import os
import sys
import tempfile
import time
import uuid
import threading
from typing import Any, Callable, Optional, Union
from urllib.parse import urlparse

__version__ = "5.4.0-codebench-shim"
__all__ = ["create_window", "start", "Window", "token",
           # Module-level cookie API
           "save_cookies", "load_cookies", "clear_cookies", "get_cookies",
           "set_cookie", "delete_cookie", "cookies_autopersist"]

# Random per-process token. Real pywebview uses this in callbacks to
# disambiguate window IDs; here we just expose a stable string so user
# code that reads `webview.token` keeps working.
token = uuid.uuid4().hex


# ─── Logging ─────────────────────────────────────────────────────────
# Print compact "[pywebview]" messages to stdout for every operation
# so the user can see exactly what the shim is doing in their terminal.
# Set CODEBENCH_PYWEBVIEW_QUIET=1 to suppress (useful in scripts that
# call webview heavily and don't want the noise).
_QUIET = bool(os.environ.get("CODEBENCH_PYWEBVIEW_QUIET"))


def _log(msg: str) -> None:
    """Print one line to stdout (visible in the in-app terminal).
    Tagged so users can grep / filter."""
    if _QUIET:
        return
    try:
        sys.stdout.write(f"[pywebview] {msg}\n")
        sys.stdout.flush()
    except Exception:
        pass


def _short_path(p: str) -> str:
    """Trim a long temp-dir path so log lines don't wrap the terminal.
    Keeps the leaf filename + the immediate parent dir for context."""
    if not p:
        return "(none)"
    parts = p.rstrip("/").split("/")
    if len(parts) >= 2:
        return ".../" + "/".join(parts[-2:])
    return p


def _short_html(s: str, n: int = 60) -> str:
    """Single-line preview of an HTML string for logs. Collapses
    whitespace, truncates with ellipsis, escapes the trailing newline."""
    flat = " ".join(s.split())
    return (flat[:n] + "…") if len(flat) > n else flat


# ─── File-IPC plumbing ───────────────────────────────────────────────
def _signal_dir() -> str:
    """Same dir LaTeXEngine.startSignalWatcher polls (every 100 ms).
    Reusing it means we get the existing Swift-side polling for free
    — no new timer to register."""
    d = os.path.join(tempfile.gettempdir(), "latex_signals")
    os.makedirs(d, exist_ok=True)
    return d


def _scratch_dir() -> str:
    """Where we drop the generated HTML files. Sub-folder so they
    don't pollute the top-level signals dir + are easy to clean up."""
    d = os.path.join(tempfile.gettempdir(), "pywebview_scratch")
    os.makedirs(d, exist_ok=True)
    return d


def _post_signal(payload: str) -> None:
    """Write the payload Swift's onPreviewRequest watches for.

    `payload` is either a local file path (.html, .pdf, .png, …) OR
    an http(s):// URL. Swift's preview controller branches on the
    scheme — http(s) gets `webView.load(URLRequest(url:))` so the
    page loads with its real origin (cookies, referer, CSP, first-
    party storage), and a file path goes through `loadFileURL(...)`.

    Atomic write via tmp + rename so the watcher never sees a half-
    written payload. The Swift side `removeItem(atPath:)`s the file
    after consuming, so successive create_window/load_url calls don't
    pile up — only the latest signal wins, matching pywebview's
    "show this window now" semantics.
    """
    sig = os.path.join(_signal_dir(), "preview_request.txt")
    tmp = sig + ".tmp"
    try:
        with open(tmp, "w", encoding="utf-8") as f:
            f.write(payload + "\n")
        os.replace(tmp, sig)
        if payload.startswith(("http://", "https://")):
            _log(f"  signal → {_short_path(sig)}  (url: {payload})")
        else:
            try:
                size = os.path.getsize(payload)
                _log(f"  signal → {_short_path(sig)}  ({size} bytes)")
            except OSError:
                _log(f"  signal → {_short_path(sig)}  (path: {payload})")
    except OSError as e:
        _log(f"  ! signal write failed: {e}")
        sys.stderr.write(f"[pywebview-shim] signal write failed: {e}\n")


def _write_html_file(content: str, prefix: str = "page") -> str:
    """Write `content` to a uniquely-named .html file in the scratch
    dir and return its absolute path. The Swift preview WebView loads
    it via `loadFileURL(...allowingReadAccessTo: parent)`, so any
    relative `<link>`/`<script src>`/`<img>` references that resolve
    inside the scratch dir will work."""
    name = f"{prefix}_{uuid.uuid4().hex[:8]}.html"
    path = os.path.join(_scratch_dir(), name)
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    return path


def _redirect_html(target_url: str) -> str:
    """Build a tiny HTML page whose only job is to navigate to
    `target_url`. Used when the user passes an http/https URL — we
    can't `loadFileURL` an http URL, but the file we DO loadFileURL
    can immediately redirect to it via meta-refresh. WebKit honors
    this even from file://."""
    # Escape <, > and &quot; so a malicious URL can't break out of
    # the meta tag attribute. (Yes, this is theoretical — no other
    # process is feeding us URLs — but cheap insurance.)
    safe = (target_url
            .replace("&", "&amp;")
            .replace('"', "&quot;")
            .replace("<", "&lt;")
            .replace(">", "&gt;"))
    return (
        f'<!doctype html><html><head>'
        f'<meta charset="utf-8">'
        f'<meta http-equiv="refresh" content="0; url={safe}">'
        f'<title>Loading…</title>'
        f'<style>body{{margin:0;background:#0a0a0f;color:#a8a8b8;'
        f'font:14px -apple-system,sans-serif;display:flex;'
        f'align-items:center;justify-content:center;height:100vh}}</style>'
        f'</head><body>Loading <code>{safe}</code>…</body></html>'
    )


# ─── Cookie management ──────────────────────────────────────────────
# Real pywebview surfaces the host browser's cookie store. We don't
# have access to WKWebView's WKHTTPCookieStore from Python (no Swift
# bridge ships in this shim), so we keep our OWN jar in Python:
#
#   • set/get/delete via the Window API mirrors the real pywebview shape
#   • cookies are auto-injected into every loaded page via JS
#     (`document.cookie = "..."`) so WKWebView's store sees them too
#   • the user controls persistence — save_cookies(path) writes JSON,
#     load_cookies(path) restores; cookies_autopersist=True enables
#     write-on-change to a default path under ~/Documents.
#
# Cookie shape (matches pywebview / browser convention):
#   {"name": str, "value": str, "domain": str, "path": str,
#    "expires": float|None, "secure": bool, "httponly": bool, "samesite": str}

DEFAULT_COOKIE_FILE = os.path.expanduser(
    "~/Documents/.codebench-pywebview-cookies.json")

# Module-level jar. Each entry is a dict in the shape above.
_cookie_jar: list[dict] = []
_cookies_lock = threading.Lock()

# Auto-persist toggle. When True, every set/delete/clear flushes the
# whole jar to DEFAULT_COOKIE_FILE so cookies survive script restarts.
# Default OFF so user code that just wants a transient session jar
# doesn't accidentally write to disk.
cookies_autopersist: bool = False


def _normalize_cookie(name: str, value: str,
                      domain: str = "", path: str = "/",
                      expires: Optional[float] = None,
                      secure: bool = False,
                      httponly: bool = False,
                      samesite: str = "Lax") -> dict:
    return {
        "name": str(name),
        "value": str(value),
        "domain": str(domain or ""),
        "path": str(path or "/"),
        "expires": float(expires) if expires is not None else None,
        "secure": bool(secure),
        "httponly": bool(httponly),
        "samesite": str(samesite),
    }


def _cookie_matches_url(c: dict, url: str) -> bool:
    """Same scoping rules a browser uses to decide whether to send a
    cookie with a request: domain suffix-match (with leading-dot rule),
    path prefix match, secure-only over https, and not-yet-expired."""
    parsed = urlparse(url)
    host = (parsed.hostname or "").lower()
    domain = (c["domain"] or "").lower().lstrip(".")
    if domain and not (host == domain or host.endswith("." + domain)):
        return False
    if c["secure"] and parsed.scheme != "https":
        return False
    if c["expires"] is not None and c["expires"] < time.time():
        return False
    if c["path"] and not (parsed.path or "/").startswith(c["path"]):
        return False
    return True


def _cookies_for_url(url: str) -> list[dict]:
    with _cookies_lock:
        return [c for c in _cookie_jar if _cookie_matches_url(c, url)]


def _build_cookie_inject_js(cookies: list[dict]) -> str:
    """JS that sets each cookie via `document.cookie = "..."` so the
    page's WKWebView cookie store picks them up. Stored in a script
    tag injected into the redirect / scratch HTML before the
    page-content load so the values are present when the target
    page actually evaluates."""
    lines = []
    for c in cookies:
        # Build a Set-Cookie-style string. Path / expires / secure /
        # samesite all live as semicolon-separated attributes.
        parts = [f'{c["name"]}={c["value"]}']
        if c["path"]:    parts.append(f'path={c["path"]}')
        if c["domain"]:  parts.append(f'domain={c["domain"]}')
        if c["expires"] is not None:
            from email.utils import formatdate
            parts.append(f'expires={formatdate(c["expires"], usegmt=True)}')
        if c["secure"]:    parts.append("secure")
        if c["samesite"]:  parts.append(f'samesite={c["samesite"]}')
        # JSON-encode so quotes / backslashes don't break the JS string.
        lines.append(f'document.cookie = {json.dumps("; ".join(parts))};')
    if not lines:
        return ""
    return ("<script>try {" + " ".join(lines) +
            "} catch (_e) {}</script>\n")


def _maybe_autopersist(reason: str) -> None:
    if cookies_autopersist:
        try:
            n = save_cookies(DEFAULT_COOKIE_FILE)
            _log(f"  auto-persisted {n} cookie(s) → "
                 f"{_short_path(DEFAULT_COOKIE_FILE)} ({reason})")
        except OSError as e:
            _log(f"  ! auto-persist failed: {e}")


def get_cookies(url: Optional[str] = None) -> list[dict]:
    """Module-level: return cookies, optionally scoped to `url`.

    With no arg: every cookie in the jar (regardless of domain).
    With a URL: only cookies that would be sent with a request to it
    (browser-style domain / path / secure scoping)."""
    with _cookies_lock:
        if url is None:
            out = list(_cookie_jar)
        else:
            out = [c for c in _cookie_jar if _cookie_matches_url(c, url)]
    _log(f"get_cookies(url={url!r}) → {len(out)} cookie(s)")
    return out


def set_cookie(name: str, value: str,
               domain: str = "", path: str = "/",
               expires: Optional[float] = None,
               secure: bool = False,
               httponly: bool = False,
               samesite: str = "Lax") -> dict:
    """Module-level: add (or overwrite) a cookie in the jar.

    Cookies are uniquely identified by (name, domain, path) — adding
    one with the same triple replaces the previous value, matching
    browser semantics. Returns the stored cookie dict."""
    new = _normalize_cookie(name, value, domain, path,
                            expires, secure, httponly, samesite)
    with _cookies_lock:
        for i, c in enumerate(_cookie_jar):
            if (c["name"] == new["name"]
                and c["domain"] == new["domain"]
                and c["path"] == new["path"]):
                _cookie_jar[i] = new
                _log(f"set_cookie({name!r}={value!r}, domain={domain!r}, "
                     f"path={path!r})  → REPLACED existing")
                _maybe_autopersist(f"set {name}")
                return new
        _cookie_jar.append(new)
    _log(f"set_cookie({name!r}={value!r}, domain={domain!r}, "
         f"path={path!r})  → ADDED  (jar now has {len(_cookie_jar)})")
    _maybe_autopersist(f"set {name}")
    return new


def delete_cookie(name: str, domain: str = "", path: str = "/") -> int:
    """Module-level: remove cookie(s) matching name + optional
    domain + path. Returns the number removed."""
    removed = 0
    with _cookies_lock:
        keep = []
        for c in _cookie_jar:
            if (c["name"] == name
                and (not domain or c["domain"] == domain)
                and (not path or c["path"] == path)):
                removed += 1
                continue
            keep.append(c)
        _cookie_jar[:] = keep
    _log(f"delete_cookie({name!r}, domain={domain!r}, path={path!r}) "
         f"→ removed {removed}, jar now has {len(_cookie_jar)}")
    if removed:
        _maybe_autopersist(f"delete {name}")
    return removed


def clear_cookies(domain: str = "") -> int:
    """Module-level: drop the entire jar, or just cookies for `domain`
    (suffix-match, e.g. `clear_cookies("example.com")` also removes
    `.api.example.com` cookies). Returns number removed."""
    with _cookies_lock:
        if not domain:
            n = len(_cookie_jar)
            _cookie_jar.clear()
        else:
            d = domain.lower().lstrip(".")
            keep = []
            n = 0
            for c in _cookie_jar:
                cd = (c["domain"] or "").lower().lstrip(".")
                if cd == d or cd.endswith("." + d):
                    n += 1
                    continue
                keep.append(c)
            _cookie_jar[:] = keep
    _log(f"clear_cookies(domain={domain!r}) → removed {n}, "
         f"jar now has {len(_cookie_jar)}")
    if n:
        _maybe_autopersist(f"clear {domain or '<all>'}")
    return n


def save_cookies(path: str = DEFAULT_COOKIE_FILE) -> int:
    """Write the jar as JSON to `path`. Atomic write via tmp+rename so
    a crash mid-write can't corrupt the file. Returns count saved."""
    path = os.path.expanduser(path)
    with _cookies_lock:
        snapshot = list(_cookie_jar)
    tmp = path + ".tmp"
    try:
        os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump({"version": 1, "saved_at": time.time(),
                       "cookies": snapshot}, f, indent=2)
        os.replace(tmp, path)
    except OSError:
        try: os.remove(tmp)
        except OSError: pass
        raise
    _log(f"save_cookies(path={_short_path(path)}) → wrote {len(snapshot)} cookie(s)")
    return len(snapshot)


def load_cookies(path: str = DEFAULT_COOKIE_FILE,
                 *, replace: bool = False) -> int:
    """Read cookies from `path` and merge into the jar. With
    `replace=True`, drop the existing jar first.

    Missing file is NOT an error — returns 0. Useful for app startup:
    `webview.load_cookies()` on launch picks up whatever was saved
    last time without barfing on a fresh install."""
    path = os.path.expanduser(path)
    if not os.path.exists(path):
        _log(f"load_cookies(path={_short_path(path)}) → file not found, "
             f"jar unchanged (returning 0)")
        return 0
    try:
        with open(path, "r", encoding="utf-8") as f:
            doc = json.load(f)
    except (OSError, json.JSONDecodeError) as e:
        _log(f"  ! load_cookies failed: {e}")
        raise
    cookies = doc.get("cookies", []) if isinstance(doc, dict) else doc
    n = 0
    with _cookies_lock:
        if replace:
            _cookie_jar.clear()
        for c in cookies:
            try:
                _cookie_jar.append(_normalize_cookie(**c))
                n += 1
            except (TypeError, KeyError):
                continue
    _log(f"load_cookies(path={_short_path(path)}, replace={replace}) "
         f"→ loaded {n} cookie(s), jar now has {len(_cookie_jar)}")
    return n


# ─── Window class ────────────────────────────────────────────────────
class Window:
    """User-visible handle returned by `create_window`. All mutating
    methods re-signal the preview pane so the user sees the change."""

    def __init__(self, title: str, url: Optional[str] = None,
                 html: Optional[str] = None,
                 js_api: Any = None, **kwargs: Any) -> None:
        self.uid: str = uuid.uuid4().hex
        self.title: str = title or "Untitled"
        self._html_path: Optional[str] = None
        self._destroyed = False
        # Initial create_window log — describes what was passed.
        if html is not None:
            _log(f"create_window(uid={self.uid[:8]}, title={self.title!r}, "
                 f"html={_short_html(html)!r})")
        elif url is not None:
            _log(f"create_window(uid={self.uid[:8]}, title={self.title!r}, "
                 f"url={url!r})")
        else:
            _log(f"create_window(uid={self.uid[:8]}, title={self.title!r}) "
                 f"  — empty window")
        if kwargs:
            _log(f"  unsupported kwargs ignored: {sorted(kwargs)}")
        if js_api is not None:
            _log(f"  ! js_api ({type(js_api).__name__}) — JS→Python callbacks "
                 f"unsupported in this shim; calls into it will silently no-op")
            sys.stderr.write(
                "[pywebview-shim] js_api is not supported in CodeBench — "
                "JS→Python callbacks would need a WKScriptMessage bridge "
                "that the shim doesn't ship. The window still renders; "
                "calls into js_api just no-op.\n")
        # Stash unsupported kwargs so user code reading them doesn't
        # AttributeError. Most are visual-only on the real impl
        # (resizable, frameless, on_top, fullscreen, transparent, …)
        self._opts = dict(kwargs)
        # Resolve the initial content.
        if url is not None and html is not None:
            _log(f"  ! both url= and html= given — html= wins (matches pywebview)")
            sys.stderr.write("[pywebview-shim] both url= and html= given — "
                             "html= wins (matches pywebview).\n")
        if html is not None:
            self.load_html(html)
        elif url is not None:
            self.load_url(url)
        else:
            self.load_html(
                f"<!doctype html><body style='font:14px sans-serif;"
                f"padding:2em'>Empty window: <b>{self.title}</b></body>")

    # ─ Public API ─

    def load_url(self, url: str) -> None:
        """Navigate the preview to `url`. Accepts http(s)://, file://,
        and bare absolute paths.

        For http(s):// the URL is sent to Swift unmodified and loaded
        via WKWebView's `URLRequest`, so the page sees its real origin
        — cookies, referer, CSP, JS, first-party storage all behave
        the way they would in a regular browser. Earlier versions of
        the shim wrapped http URLs in a file:// meta-refresh redirect
        page, but that broke many sites' interactive controls (form
        submits, OAuth callbacks, postMessage handlers tied to origin)
        because the page was effectively running in the file:// origin
        for the brief moment before the redirect, and some controls
        bound their listeners during that window.
        """
        if self._destroyed:
            _log(f"load_url(uid={self.uid[:8]}, url={url!r})  — IGNORED (destroyed)")
            return
        parsed = urlparse(url)
        if parsed.scheme in ("http", "https"):
            # Cookies in the shim's jar can't be injected into a
            # direct-load — there's no HTML wrapper to hold the
            # `document.cookie = ...` JS. The user can call
            # `w.evaluate_js("document.cookie = '...';")` after the
            # page loads if they need the legacy behavior.
            scoped = _cookies_for_url(url)
            if scoped:
                _log(f"  ! {len(scoped)} jar cookie(s) for {parsed.hostname} "
                     f"NOT injected (direct URL load — use evaluate_js to set)")
            self._html_path = url           # used for get_current_url()
            kind = "http(s) → direct WKWebView URLRequest (real origin)"
            _log(f"load_url(uid={self.uid[:8]}, url={url!r})  → {kind}")
            _post_signal(url)
            return
        if parsed.scheme == "file":
            kind = "file:// (sibling assets resolve)"
            self._html_path = parsed.path
        elif os.path.isabs(url) and os.path.exists(url):
            kind = "absolute path (sibling assets resolve)"
            self._html_path = url
        else:
            kind = "unknown scheme — building redirect page"
            self._html_path = _write_html_file(
                _redirect_html(url), prefix="redirect")
        _log(f"load_url(uid={self.uid[:8]}, url={url!r})  → {kind}")
        _log(f"  scratch html → {_short_path(self._html_path)}")
        _post_signal(self._html_path)

    def load_html(self, content: str) -> None:
        """Replace the window's content with `content` (raw HTML)."""
        if self._destroyed:
            _log(f"load_html(uid={self.uid[:8]}) — IGNORED (destroyed)")
            return
        _log(f"load_html(uid={self.uid[:8]}, {len(content)} chars: "
             f"{_short_html(content)!r})")
        self._html_path = _write_html_file(content, prefix="page")
        _log(f"  scratch html → {_short_path(self._html_path)}")
        _post_signal(self._html_path)

    def evaluate_js(self, script: str,
                    callback: Optional[Callable[[Any], None]] = None) -> None:
        """Inject `script` into the page by appending an inline
        <script> tag and re-loading. NOT a real eval — there's no JS-
        return-value path back to Python without a WKScriptMessage
        bridge — but it covers the common "set window.foo / mutate
        DOM" use case. `callback` is invoked with None."""
        if self._destroyed or self._html_path is None:
            _log(f"evaluate_js(uid={self.uid[:8]}) — IGNORED "
                 f"({'destroyed' if self._destroyed else 'no current page'})")
            return
        # The shim can only rewrite scratch HTML files. After a direct
        # http(s) load the "current page" is a remote URL — there's no
        # local file to append a <script> tag into, and we have no
        # WKScriptMessage bridge to evaluateJavaScript on the live
        # WebView. So no-op with a clear log line.
        if self._html_path.startswith(("http://", "https://")):
            _log(f"evaluate_js(uid={self.uid[:8]}) — NO-OP "
                 f"(current page is a remote URL; shim has no live "
                 f"JS bridge to WKWebView)")
            if callback is not None:
                try: callback(None)
                except Exception as e:
                    _log(f"  ! callback raised: {e}")
            return
        _log(f"evaluate_js(uid={self.uid[:8]}, {len(script)} chars: "
             f"{_short_html(script, 50)!r})")
        try:
            current = open(self._html_path, encoding="utf-8").read()
        except OSError as e:
            _log(f"  ! couldn't read scratch html: {e}")
            return
        snippet = f'\n<script>try {{ {script} }} catch(_e){{}}</script>'
        if "</body>" in current:
            new = current.replace("</body>", snippet + "</body>", 1)
        else:
            new = current + snippet
        try:
            with open(self._html_path, "w", encoding="utf-8") as f:
                f.write(new)
            _post_signal(self._html_path)
        except OSError as e:
            _log(f"  ! couldn't rewrite scratch html: {e}")
        if callback is not None:
            _log(f"  callback({type(callback).__name__}) invoked with None "
                 f"(no JS return-value bridge in this shim)")
            try: callback(None)
            except Exception as e:
                _log(f"  ! callback raised: {e}")

    def set_title(self, title: str) -> None:
        """Change the window title. The preview pane doesn't show
        a title bar (it's the side pane), so this just updates our
        cached `title` for any user code that reads it back."""
        _log(f"set_title(uid={self.uid[:8]}) {self.title!r} → {title!r}")
        self.title = title

    def get_current_url(self) -> Optional[str]:
        """Returns the URL the preview pane was last asked to load.

        For http(s):// loads, this is the URL passed to load_url
        verbatim. For local content (load_html or file:// load_url),
        it's the file:// URL of the scratch / source HTML."""
        if self._html_path is None:
            _log(f"get_current_url(uid={self.uid[:8]}) → None")
            return None
        if self._html_path.startswith(("http://", "https://")):
            url = self._html_path
        else:
            url = f"file://{self._html_path}"
        _log(f"get_current_url(uid={self.uid[:8]}) → {url}")
        return url

    def get_size(self) -> tuple[int, int]:
        """Stubbed — the in-app preview pane is sized by the user's
        editor split, not by pywebview. Return (0, 0) so anyone
        gating on a non-zero size knows."""
        _log(f"get_size(uid={self.uid[:8]}) → (0, 0)  (pane-sized, "
             f"shim can't query)")
        return (0, 0)

    def show(self) -> None:
        """No-op — the preview pane is always visible if there's
        content to show."""
        if self._html_path is not None:
            _log(f"show(uid={self.uid[:8]})  — re-signalling scratch html")
            _post_signal(self._html_path)
        else:
            _log(f"show(uid={self.uid[:8]})  — no scratch html to re-signal")

    # ─ Cookie API (forwards to module-level jar — windows share state) ─

    def get_cookies(self) -> list[dict]:
        """Cookies that would apply to this window's current URL.

        If the window was loaded from a local file (no domain), returns
        ALL cookies in the jar — there's no domain to filter on. Real
        pywebview returns http.cookiejar.Cookie objects; here we use
        plain dicts (same shape) which are easier to inspect / pickle
        / send over JSON."""
        url = self.get_current_url() or ""
        # Strip the file:// prefix so the URL parser doesn't treat the
        # filesystem path as a hostname (which would always miss).
        if url.startswith("file://"):
            return get_cookies()  # all cookies — no domain to filter
        return get_cookies(url)

    def set_cookie(self, name: str, value: str, **kwargs: Any) -> dict:
        """Add a cookie to the jar. See module-level set_cookie for kwargs."""
        return set_cookie(name, value, **kwargs)

    def delete_cookie(self, name: str, domain: str = "", path: str = "/") -> int:
        """Remove cookie(s) from the jar. Returns count removed."""
        return delete_cookie(name, domain=domain, path=path)

    def clear_cookies(self, domain: str = "") -> int:
        """Drop the entire jar (or just this domain). Returns count removed."""
        return clear_cookies(domain=domain)

    def save_cookies(self, path: str = DEFAULT_COOKIE_FILE) -> int:
        """Write the jar to disk. Returns count saved."""
        return save_cookies(path)

    def load_cookies(self, path: str = DEFAULT_COOKIE_FILE,
                     *, replace: bool = False) -> int:
        """Load cookies from disk into the jar. Returns count loaded."""
        return load_cookies(path, replace=replace)

    def hide(self) -> None:
        """Best-effort: replace content with a blank page. The user
        can still bring it back with `show()` because we keep
        `_html_path`."""
        _log(f"hide(uid={self.uid[:8]})  — replacing preview with blank page")
        blank = _write_html_file(
            "<!doctype html><body style='background:#0a0a0f'></body>",
            prefix="blank")
        _post_signal(blank)

    def destroy(self) -> None:
        """Mark the window dead — subsequent load_url / load_html
        calls become no-ops. Doesn't actually clear the preview
        because closing it would be confusing if the user ran the
        script just to render that one chart."""
        _log(f"destroy(uid={self.uid[:8]})  — window marked destroyed; "
             f"subsequent load_* calls are no-ops")
        self._destroyed = True


# ─── Module-level API ────────────────────────────────────────────────
# Real pywebview tracks all created windows here; user code
# occasionally reads `webview.windows[0]`.
windows: list[Window] = []


def create_window(title: str,
                  url: Optional[str] = None,
                  html: Optional[str] = None,
                  js_api: Any = None,
                  **kwargs: Any) -> Window:
    """Mirror of `webview.create_window`. Returns a Window handle.

    On real pywebview the window is added to a global list and only
    actually shown when `start()` is called. Here we render
    immediately (the user expects to see SOMETHING when they call
    create_window in a script), but `start()` still works as the
    documented "blocks until windows close" entry point — it just
    blocks on the same threading.Event the shim exits on.
    """
    w = Window(title, url=url, html=html, js_api=js_api, **kwargs)
    windows.append(w)
    return w


_started = threading.Event()


def start(func: Optional[Callable[..., Any]] = None,
          args: tuple = (),
          *_extra_args,
          **_extra_kwargs) -> None:
    """Real pywebview blocks until all windows close. We can't
    enforce that on the in-app preview (the pane stays visible),
    so we run `func(*args)` if given (mirrors pywebview's "do work
    after the GUI is up" hook) and then return immediately. User
    scripts that called `webview.start()` to keep the process alive
    can poll on their own — exiting Python here doesn't tear down
    the app, so there's no harm in returning.
    """
    _started.set()
    n = len(windows)
    _log(f"start()  — {n} window(s) registered, returning immediately "
         f"(real pywebview would block; the in-app preview pane is always live)")
    if func is not None:
        _log(f"  invoking start() callback {func.__name__ if hasattr(func, '__name__') else func!r}"
             f"({len(args)} args)")
        try:
            func(*args)
            _log(f"  callback returned cleanly")
        except Exception as e:
            _log(f"  ! callback raised: {type(e).__name__}: {e}")
            sys.stderr.write(f"[pywebview-shim] start() callback raised: {e}\n")


# Surface a couple of attributes the real package exposes so user
# code that reads webview.menu / webview.dom / webview.guilib doesn't
# AttributeError. Their values are None because we don't implement
# the corresponding functionality.
menu = None
dom = None
guilib = "codebench"  # human-readable backend identifier
